.darma-loader-glow-pulse {
  display: inline-block;
  width: 46px;
  height: 46px;
  border-radius: 50%;
  background: var(--loader-color, #6366f1);
  box-shadow: 0 0 0 0 color-mix(in srgb, var(--loader-color, #6366f1) 42%, transparent);
  animation: darma-loader-glow-pulse-glow 1.1s ease-in-out infinite;
}
@keyframes darma-loader-glow-pulse-glow {
  0%, 100% { transform: scale(0.9); box-shadow: 0 0 0 0 color-mix(in srgb, var(--loader-color, #6366f1) 42%, transparent); }
  50% { transform: scale(1); box-shadow: 0 0 0 18px transparent; }
}

.darma-loader-heartbeat-pulse {
  display: inline-block;
  width: 50px;
  height: 50px;
  border-radius: 18px;
  background: var(--loader-color, #6366f1);
  transform: rotate(45deg);
  animation: darma-loader-heartbeat-pulse-heartbeat 1.05s ease-in-out infinite;
}
@keyframes darma-loader-heartbeat-pulse-heartbeat {
  0%, 100% { transform: rotate(45deg) scale(0.9); opacity: 0.7; }
  30% { transform: rotate(45deg) scale(1.05); opacity: 1; }
  45% { transform: rotate(45deg) scale(0.92); }
  60% { transform: rotate(45deg) scale(1.08); }
}

.darma-loader-uiverse-pink-pulse-ring {
  display: inline-block;
  width: 50px;
  height: 50px;
  border-radius: 50%;
  border: 3px solid var(--loader-color, #22c55e);
  animation: darma-loader-uiverse-pink-pulse-ring-ringPulse 1.15s ease-out infinite;
}
@keyframes darma-loader-uiverse-pink-pulse-ring-ringPulse { 0% { transform: scale(.45); opacity: 1; } 100% { transform: scale(1.15); opacity: 0; } }

.darma-loader-pulse-ring {
  position: relative;
  display: inline-block;
  width: 54px;
  height: 54px;
  border-radius: 50%;
  background: var(--loader-color, #6366f1);
}
.darma-loader-pulse-ring::before,
.darma-loader-pulse-ring::after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  border: 3px solid var(--loader-color, #6366f1);
  animation: darma-loader-pulse-ring-pulse 1.25s ease-out infinite;
}
.darma-loader-pulse-ring::after { animation-delay: 0.45s; }
@keyframes darma-loader-pulse-ring-pulse {
  to { transform: scale(1.9); opacity: 0; }
}
